import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(home: SliverDemo()));

class SliverDemo extends StatelessWidget {
  const SliverDemo({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    body: CustomScrollView(
      slivers: [
        // 1. Collapsing app bar with expanded background image
        SliverAppBar(
          expandedHeight: 240,
          pinned: true,               // header stays visible when collapsed
          flexibleSpace: FlexibleSpaceBar(
            title: const Text('Sliver Demo'),
            background: Image.network(
              'https://picsum.photos/800/400',
              fit: BoxFit.cover,
            ),
          ),
        ),

        // 2. A single non-scrolling widget inside the scroll
        const SliverToBoxAdapter(
          child: Padding(
            padding: EdgeInsets.all(16),
            child: Text('Featured', style: TextStyle(fontSize: 22)),
          ),
        ),

        // 3. A grid section
        SliverPadding(
          padding: const EdgeInsets.symmetric(horizontal: 16),
          sliver: SliverGrid(
            gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
              crossAxisCount: 3, mainAxisSpacing: 8, crossAxisSpacing: 8,
            ),
            delegate: SliverChildBuilderDelegate(
              (context, i) => Container(
                color: Colors.primaries[i % Colors.primaries.length].shade200,
                child: Center(child: Text('$i')),
              ),
              childCount: 9,
            ),
          ),
        ),

        // 4. Another header, then a list
        const SliverToBoxAdapter(
          child: Padding(
            padding: EdgeInsets.all(16),
            child: Text('All items', style: TextStyle(fontSize: 22)),
          ),
        ),
        SliverList(
          delegate: SliverChildBuilderDelegate(
            (context, i) => ListTile(
              leading: const Icon(Icons.article),
              title: Text('Item $i'),
            ),
            childCount: 100,
          ),
        ),
      ],
    ),
  );
}

// Try it: the app bar collapses as you scroll → shows a small header → the
// grid stays put → the list scrolls under it. All in ONE CustomScrollView.
